INSERT INTO articles (slug, title, content, source, category) VALUES
('dao-de-jing-chapter-31', '道德经·第三十一章', '夫佳兵者，不祥之器，物或恶之，故有道者不处。君子居则贵左，用兵则贵右。兵者不祥之器，非君子之器，不得已而用之，恬淡为上。胜而不美，而美之者，是乐杀人。夫乐杀人者，则不可得志于天下矣。吉事尚左，凶事尚右。偏将军居左，上将军居右，言以丧礼处之。杀人之众，以悲哀泣之，战胜以丧礼处之。', '老子', 'classics'),
('dao-de-jing-chapter-32', '道德经·第三十二章', '道常无名。朴虽小，天下莫能臣。侯王若能守之，万物将自宾。天地相合，以降甘露，民莫之令而自均。始制有名，名亦既有，夫亦将知止，知止可以不殆。譬道之在天下，犹川谷之于江海。', '老子', 'classics'),
('dao-de-jing-chapter-33', '道德经·第三十三章', '知人者智，自知者明。胜人者有力，自胜者强。知足者富。强行者有志。不失其所者久。死而不亡者寿。', '老子', 'classics'),
('dao-de-jing-chapter-34', '道德经·第三十四章', '大道泛兮，其可左右。万物恃之以生而不辞，功成不名有。衣养万物而不为主，常无欲，可名于小；万物归焉而不为主，可名为大。以其终不自为大，故能成其大。', '老子', 'classics'),
('dao-de-jing-chapter-35', '道德经·第三十五章', '执大象，天下往。往而不害，安平太。乐与饵，过客止。道之出口，淡乎其无味，视之不足见，听之不足闻，用之不足既。', '老子', 'classics'),
('dao-de-jing-chapter-36', '道德经·第三十六章', '将欲歙之，必固张之；将欲弱之，必固强之；将欲废之，必固兴之；将欲取之，必固与之。是谓微明。柔弱胜刚强。鱼不可脱于渊，国之利器不可以示人。', '老子', 'classics'),
('dao-de-jing-chapter-37', '道德经·第三十七章', '道常无为而无不为。侯王若能守之，万物将自化。化而欲作，吾将镇之以无名之朴。镇之以无名之朴，夫亦将不欲。不欲以静，天下将自定。', '老子', 'classics'),
('dao-de-jing-chapter-38', '道德经·第三十八章', '上德不德，是以有德；下德不失德，是以无德。上德无为而无以为；下德无为而有以为。上仁为之而无以为；上义为之而有以为。上礼为之而莫之应，则攘臂而扔之。故失道而后德，失德而后仁，失仁而后义，失义而后礼。夫礼者，忠信之薄，而乱之首。前识者，道之华，而愚之始。是以大丈夫处其厚，不居其薄；处其实，不居其华。故去彼取此。', '老子', 'classics'),
('dao-de-jing-chapter-39', '道德经·第三十九章', '昔之得一者：天得一以清；地得一以宁；神得一以灵；谷得一以生；侯王得一以为天下正。其致之也，谓天无以清，将恐裂；地无以宁，将恐废；神无以灵，将恐歇；谷无以盈，将恐竭；万物无以生，将恐灭；侯王无以正，将恐蹶。故贵以贱为本，高以下为基。是以侯王自谓孤、寡、不谷。此非以贱为本邪？非乎？故至誉无誉。是故不欲琭琭如玉，珞珞如石。', '老子', 'classics'),
('dao-de-jing-chapter-40', '道德经·第四十章', '反者道之动；弱者道之用。天下万物生于有，有生于无。', '老子', 'classics');